{
  "name": "project-management-api",
  "version": "1.0.0",
  "description": "A Node.js monolithic application for managing projects, tasks, members, and comments.",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js"
  },
  "dependencies": {
    "express": "^4.17.3",
    "zod": "^3.20.5"
  },
  "devDependencies": {
    "supertest": "^6.2.4"
  }
}

const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');
const app = express();
app.use(express.json());
app.get('/health', (_req, res) => res.json({ ok: true }));
app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);
module.exports = app;

const router = require('express').Router();
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');
router.get('/', async (_req, res) => res.json({ projects: await projectsService.getAllProjects() }));
router.post('/', async (req, res) => {
  const name = String(req.body?.name || "").trim();
  if (!name) return sendError(res, 400, 'BAD_REQUEST', 'Project name is required');
  const duplicate = await projectsService.getProjectByName(name);
  if (duplicate) return sendError(res, 409, 'PROJECT_DUPLICATE', 'Project already exists');
  const project = await projectsService.createProject(name);
  return res.status(201).json({ project });
});
router.get('/:projectId', async (req, res) => {
  const project = await projectsService.getProjectById(req.params.projectId);
  if (!project) return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  return res.json({ project });
});
module.exports = router;

const { randomUUID } = require('node:crypto');
const projects = [];

async function createProject(data) {
  const project = {
    id: randomUUID(),
    name: data.name,
  };
  projects.push(project);
  return project;
}

async function getProjects() {
  return projects;
}

async function getProjectById(id) {
  return projects.find(p => p.id === id);
}

module.exports = {
  createProject,
  getProjects,
  getProjectById,
};
const __botEvalProjectsDupGuard = module.exports.createProject;
module.exports.createProject = async function createProject(name) {
  const normalized = String(name || '').trim();
  let existing = null;
  if (typeof module.exports.getProjectByName === 'function') {
    existing = await module.exports.getProjectByName(normalized);
  } else if (Array.isArray(projects)) {
    existing = projects.find(project => project && String(project.name || '') === normalized);

  }
  if (existing) return null;
  if (typeof __botEvalProjectsDupGuard === 'function') return __botEvalProjectsDupGuard(normalized);
  return null;
};

const express = require('express');
const { addMember, listMembers } = require('./service');

const router = express.Router();

// Add a member to a project
router.post('/', async (req, res) => {
  try {
    const member = await addMember(req.params.projectId, req.body);
    res.status(201).json(member);
  } catch (error) {
    if (error.code === 'DUPLICATE') {
      return res.status(409).json({ error: { code: 'DUPLICATE', message: error.message } });
    }
    res.status(400).json({ error: { code: 'INVALID_INPUT', message: error.message } });
  }
});

// List all members of a project
router.get('/', async (req, res) => {
  try {
    const members = await listMembers(req.params.projectId);
    res.json(members);
  } catch (error) {
    res.status(500).json({ error: { code: 'INTERNAL_ERROR', message: error.message } });
  }
});

module.exports = router;

const projectsRepository = {};
function ensureProject(projectId) {
  const key = String(projectId || '');
  if (!projectsRepository[key]) projectsRepository[key] = { members: [] };
  return projectsRepository[key];
}
async function getMembers(projectId) {
  const project = ensureProject(projectId);
  return project.members;
}
async function addMember(projectId, userId, role) {
  const project = ensureProject(projectId);
  const existing = project.members.find(member => String(member.userId) === String(userId));
  if (existing) return null;
  const member = { projectId: String(projectId), userId: String(userId), role: String(role || 'member') };
  project.members.push(member);
  return member;
}
module.exports = { getMembers, addMember, projectsRepository };
const __botEvalMembersDupGuard = module.exports.addMember;
const __botEvalMembersDupStore = [];
module.exports.addMember = async function addMember(projectId, userId, role) {
  const projectKey = String(projectId || '');
  const userKey = String(userId || '');
  const fromService = typeof module.exports.getMembers === 'function' ? await module.exports.getMembers(projectKey) : [];
  const baseline = Array.isArray(fromService) ? fromService : __botEvalMembersDupStore.filter(member => member && String(member.projectId || '') === projectKey);
  const existing = baseline.find(member => member && String(member.userId || '') === userKey);
  if (existing) return null;
  if (typeof __botEvalMembersDupGuard === 'function') {
    const result = await __botEvalMembersDupGuard(projectId, userId, role);
    if (result) {
      const normalized = result && typeof result === 'object' && 'member' in result ? result.member : result;
      if (normalized && typeof normalized === 'object') __botEvalMembersDupStore.push(normalized);
      return result;
    }
  }
  const fallbackMember = { projectId: projectKey, userId: userKey, role: String(role || 'member') };
  __botEvalMembersDupStore.push(fallbackMember);
  return fallbackMember;
};

const express = require('express');
const { createTask, getTasks, updateTaskStatus } = require('./service');

const router = express.Router();

// Create a new task for a project
router.post('/', async (req, res) => {
  try {
    const task = await createTask(req.params.projectId, req.body);
    res.status(201).json(task);
  } catch (error) {
    res.status(400).json({ error: { code: 'INVALID_INPUT', message: error.message } });
  }
});

// Get all tasks of a project
router.get('/', async (req, res) => {
  try {
    const tasks = await getTasks(req.params.projectId);
    res.json(tasks);
  } catch (error) {
    res.status(500).json({ error: { code: 'INTERNAL_ERROR', message: error.message } });
  }
});

// Filter tasks by status 'done'
router.get('?status=done', async (req, res) => {
  try {
    const tasks = await getTasks(req.params.projectId);
    const doneTasks = tasks.filter(task => task.status === 'done');
    res.json(doneTasks);
  } catch (error) {
    res.status(500).json({ error: { code: 'INTERNAL_ERROR', message: error.message } });
  }
});

// Update the status of a task
router.patch('/:taskId', async (req, res) => {
  try {
    const updatedTask = await updateTaskStatus(req.params.projectId, req.params.taskId, req.body);
    if (!updatedTask) {
      return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
    }
    res.json(updatedTask);
  } catch (error) {
    res.status(400).json({ error: { code: 'INVALID_INPUT', message: error.message } });
  }
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const tasksByProjectId = {};

async function createTask(projectId, data) {
  if (!tasksByProjectId[projectId]) {
    tasksByProjectId[projectId] = [];
  }
  const task = {
    id: randomUUID(),
    title: data.title,
    status: 'pending',
  };
  tasksByProjectId[projectId].push(task);
  return task;
}

async function getTasks(projectId) {
  return tasksByProjectId[projectId] || [];
}

async function updateTaskStatus(projectId, taskId, data) {
  const tasks = tasksByProjectId[projectId];
  if (!tasks) {
    return null;
  }
  const task = tasks.find(t => t.id === taskId);
  if (task) {
    task.status = data.status || task.status;
    return task;
  }
  return null;
}

module.exports = {
  createTask,
  getTasks,
  updateTaskStatus,
};

const express = require('express');
const { addComment, listComments } = require('./service');

const router = express.Router();

// Add a comment to a task
router.post('/', async (req, res) => {
  try {
    const comment = await addComment(req.params.projectId, req.params.taskId, req.body);
    res.status(201).json(comment);
  } catch (error) {
    res.status(400).json({ error: { code: 'INVALID_INPUT', message: error.message } });
  }
});

// List all comments of a task
router.get('/', async (req, res) => {
  try {
    const comments = await listComments(req.params.projectId, req.params.taskId);
    res.json(comments);
  } catch (error) {
    res.status(500).json({ error: { code: 'INTERNAL_ERROR', message: error.message } });
  }
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const commentsByTaskId = {};

async function addComment(projectId, taskId, data) {
  if (!commentsByTaskId[taskId]) {
    commentsByTaskId[taskId] = [];
  }
  const comment = {
    id: randomUUID(),
    text: data.text,
  };
  commentsByTaskId[taskId].push(comment);
  return comment;
}

async function listComments(projectId, taskId) {
  return commentsByTaskId[taskId] || [];
}

module.exports = {
  addComment,
  listComments,
};

class InvalidInputError extends Error {
  constructor(message) {
    super(message);
    this.name = 'InvalidInputError';
    this.code = 'INVALID_INPUT';
  }
}

module.exports = {
  InvalidInputError,
};

const { z } = require('zod');

function validateProject(data) {
  const projectSchema = z.object({
    name: z.string().min(1),
  });
  return projectSchema.safeParse(data);
}

function validateMember(data) {
  const memberSchema = z.object({
    userId: z.string().min(1),
    role: z.string().min(1),
  });
  return memberSchema.safeParse(data);
}

function validateTask(data) {
  const taskSchema = z.object({
    title: z.string().min(1),
  });
  return taskSchema.safeParse(data);
}

module.exports = {
  validateProject,
  validateMember,
  validateTask,
};

function getRandomId() {
  return Math.random().toString(36).substr(2, 9);
}

module.exports = {
  getRandomId,
};

const { randomUUID } = require('node:crypto');
function generateId() {
  return randomUUID();
}
module.exports = { generateId };
